 10→interface PostCardProps {
 11→  title: string;
 12→  bodyPreview: string;
 13→  authorName: string;
 14→  authorAvatar?: string | null;
 15→  authorBadge?: 'legend' | 'og' | null;
 16→  bannerImage?: string | null;
 17→  postType?: string;
 18→  readingTime?: string;
 19→  likeCount: number;
 20→  commentCount: number;
 21→  bookmarkCount?: number;
 22→  isLiked?: boolean;
 23→  isBookmarked?: boolean;
 24→  userReaction?: string | null;
 25→  onPress?: () => void;
 26→  onLike?: () => void;
 27→  onComment?: () => void;
 28→  onBookmark?: () => void;
 29→  onRepost?: () => void;
 30→  onReact?: (type: string) => void;
 31→  onAuthorPress?: () => void;
 32→  isRepost?: boolean;
 33→  repostCaption?: string | null;
 34→  repostSourceTitle?: string | null;
 35→  repostSourcePreview?: string | null;
 36→  repostSourceAuthorName?: string | null;
 37→  repostSourceAuthorAvatar?: string | null;
 38→  onEmbeddedPress?: () => void;
 39→}
