 41→export function PostCard({
 42→  title,
 43→  bodyPreview,
 44→  authorName,
 45→  authorAvatar,
 46→  authorBadge,
 47→  bannerImage,
 48→  postType,
 49→  readingTime,
 50→  likeCount,
 51→  commentCount,
 52→  bookmarkCount,
 53→  isLiked,
 54→  isBookmarked,
 55→  userReaction,
 56→  onPress,
 57→  onLike,
 58→  onComment,
 59→  onBookmark,
 60→  onRepost,
 61→  onReact,
 62→  onAuthorPress,
 63→  isRepost,
 64→  repostCaption,
 65→  repostSourceTitle,
 66→  repostSourcePreview,
 67→  repostSourceAuthorName,
 68→  repostSourceAuthorAvatar,
 69→  onEmbeddedPress,
 70→}: PostCardProps) {
 71→  const {colors} = useTheme();
 72→  const s = shadows(colors);
 73→
 74→  const hasSource = !!(repostSourceTitle || repostSourcePreview || repostSourceAuthorName);
 75→
 76→  return (
 77→    <Pressable
 78→      onPress={onPress}
 79→      style={({pressed}) => [
 80→        styles.card,
 81→        {
 82→          backgroundColor: colors.bgCard,
 83→          borderColor: colors.borderCard,
 84→        },
 85→        s.card,
 86→        pressed && styles.pressed,
 87→      ]}>
 88→      {isRepost ? (
 89→        <>
 90→          {/* Repost badge header */}
 91→          <View style={styles.repostBadge}>
 92→            <RepostIcon size={14} color={colors.textFaint} />
 93→            <Text style={[styles.repostBadgeText, {color: colors.textFaint}]}>
 94→              <Text style={[styles.repostBadgeName, {color: colors.textSecondary}]}>
 95→                {authorName}
 96→              </Text>
 97→              {' reposted'}
 98→            </Text>
 99→          </View>
100→
101→          <View style={styles.content}>
102→            {/* Repost caption */}
103→            {repostCaption ? (
104→              <Text style={[styles.repostCaption, {color: colors.textBody}]}>
105→                {repostCaption}
106→              </Text>
107→            ) : null}
108→
109→            {/* Embedded original post card */}
110→            {hasSource ? (
111→              <Pressable
112→                onPress={onEmbeddedPress}
113→                style={[
114→                  styles.embeddedCard,
115→                  {borderColor: colors.borderCard, backgroundColor: colors.bgPrimary},
116→                ]}>
117→                <View style={styles.embeddedAuthorRow}>
118→                  <Avatar
119→                    uri={repostSourceAuthorAvatar}
120→                    name={repostSourceAuthorName ?? ''}
121→                    size={20}
122→                  />
123→                  <Text
124→                    style={[styles.embeddedAuthorName, {color: colors.textSecondary}]}
125→                    numberOfLines={1}>
126→                    {repostSourceAuthorName}
127→                  </Text>
128→                </View>
129→                {repostSourceTitle ? (
130→                  <Text
131→                    style={[styles.embeddedTitle, {color: colors.textHeading}]}
132→                    numberOfLines={2}>
133→                    {repostSourceTitle}
134→                  </Text>
135→                ) : null}
136→                {repostSourcePreview ? (
137→                  <Text
138→                    style={[styles.embeddedPreview, {color: colors.textBody}]}
139→                    numberOfLines={3}>
140→                    {repostSourcePreview}
141→                  </Text>
142→                ) : null}
143→              </Pressable>
144→            ) : (
145→              <View
146→                style={[
147→                  styles.embeddedCard,
148→                  {borderColor: colors.borderCard, backgroundColor: colors.bgPrimary},
149→                ]}>
150→                <Text style={[styles.repostUnavailable, {color: colors.textFaint}]}>
151→                  This post is no longer available
152→                </Text>
153→              </View>
154→            )}
155→          </View>
156→        </>
157→      ) : (
158→        <>
159→          {bannerImage ? (
160→            <Image
161→              source={{uri: bannerImage}}
162→              style={styles.banner}
163→              resizeMode="cover"
164→            />
165→          ) : null}
166→
167→          <View style={styles.content}>
168→            {/* Author row */}
169→            <View style={styles.authorRow}>
170→              <Pressable
171→                style={styles.authorTouchable}
172→                onPress={onAuthorPress}
173→                disabled={!onAuthorPress}>
174→                <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
175→                <Text
176→                  style={[styles.authorName, {color: colors.textSecondary}]}
177→                  numberOfLines={1}>
178→                  {authorName}
179→                </Text>
180→                {authorBadge ? <BadgeCheckIcon size={14} badge={authorBadge} /> : null}
181→              </Pressable>
182→              {postType && postType !== 'journal' ? (
183→                <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
184→                  <Text style={[styles.typeText, {color: colors.accentSage}]}>
185→                    {postType}
186→                  </Text>
187→                </View>
188→              ) : null}
189→              {readingTime ? (
190→                <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
191→                  <Text style={[styles.typeText, {color: colors.accentSage}]}>
192→                    {readingTime}
193→                  </Text>
194→                </View>
195→              ) : null}
196→            </View>
197→
198→            {/* Title */}
199→            <Text
200→              style={[styles.title, {color: colors.textHeading}]}
201→              numberOfLines={2}>
202→              {title}
203→            </Text>
204→
205→            {/* Body preview */}
206→            {bodyPreview ? (
207→              <Text
208→                style={[styles.body, {color: colors.textBody}]}
209→                numberOfLines={3}>
210→                {bodyPreview}
211→              </Text>
212→            ) : null}
213→          </View>
214→        </>
215→      )}
216→
217→      <ActionBar
218→        likeCount={likeCount}
219→        commentCount={commentCount}
220→        bookmarkCount={bookmarkCount}
221→        isLiked={isLiked}
222→        isBookmarked={isBookmarked}
223→        userReaction={userReaction}
224→        onLike={onLike}
225→        onComment={onComment}
226→        onBookmark={onBookmark}
227→        onRepost={onRepost}
228→        onReact={onReact}
229→      />
230→    </Pressable>
231→  );
232→}
