  1→import React, {useMemo, useState} from 'react';
  2→import {FlatList, Pressable, ScrollView, StyleSheet, Text, View} from 'react-native';
  3→import {useQuery} from '@tanstack/react-query';
  4→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
  5→import {CompositeScreenProps} from '@react-navigation/native';
  6→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  7→import {SafeAreaView} from 'react-native-safe-area-context';
  8→import {SearchInput} from '../../components/SearchInput';
  9→import {Chip} from '../../components/Chip';
 10→import {Avatar} from '../../components/Avatar';
 11→import {EmptyState} from '../../components/EmptyState';
 12→import {SearchIcon} from '../../components/icons';
 13→import {useTheme} from '../../theme/ThemeProvider';
 14→import {fonts, typeScale} from '../../theme/typography';
 15→import {spacing, radii} from '../../theme/spacing';
 16→import {mobileApi} from '../../lib/api/mobileApi';
 17→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 18→
 19→type Props = CompositeScreenProps<
 20→  BottomTabScreenProps<MainTabParamList, 'Explore'>,
 21→  NativeStackScreenProps<RootStackParamList>
 22→>;
 23→
 24→type Tab = 'all' | 'users' | 'posts';
 25→
 26→export function ExploreScreen({navigation}: Props) {
 27→  const {colors} = useTheme();
 28→  const [query, setQuery] = useState('');
 29→  const [activeTab, setActiveTab] = useState<Tab>('all');
 30→  const normalizedQuery = useMemo(() => query.trim(), [query]);
 31→
 32→  const usersQuery = useQuery({
 33→    queryKey: ['search-users', normalizedQuery],
 34→    enabled: normalizedQuery.length >= 2 && activeTab !== 'posts',
 35→    queryFn: () => mobileApi.searchUsers(normalizedQuery, 10),
 36→  });
 37→
 38→  const journalsQuery = useQuery({
 39→    queryKey: ['search-journals', normalizedQuery],
 40→    enabled: normalizedQuery.length >= 2 && activeTab !== 'users',
 41→    queryFn: () => mobileApi.searchJournals(normalizedQuery, 10),
 42→  });
 43→
 44→  const users = usersQuery.data?.data ?? [];
 45→  const journals = journalsQuery.data?.data ?? [];
 46→
 47→  return (
 48→    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
 49→      <View style={styles.container}>
 50→        {/* Header */}
 51→        <View style={styles.header}>
 52→          <Text style={[styles.title, {color: colors.textHeading}]}>Explore</Text>
 53→          <SearchInput
 54→            placeholder="Search users or posts..."
 55→            value={query}
 56→            onChangeText={setQuery}
 57→            autoCapitalize="none"
 58→            returnKeyType="search"
 59→          />
 60→        </View>
 61→
 62→        {/* Tab filters */}
 63→        <ScrollView
 64→          horizontal
 65→          showsHorizontalScrollIndicator={false}
 66→          contentContainerStyle={styles.tabRow}>
 67→          {(['all', 'users', 'posts'] as Tab[]).map(tab => (
 68→            <Chip
 69→              key={tab}
 70→              label={tab.charAt(0).toUpperCase() + tab.slice(1)}
 71→              active={activeTab === tab}
 72→              onPress={() => setActiveTab(tab)}
 73→            />
 74→          ))}
 75→        </ScrollView>
 76→
 77→        {normalizedQuery.length < 2 ? (
 78→          <EmptyState
 79→            icon={<SearchIcon size={40} color={colors.textFaint} />}
 80→            title="Search iskrib"
 81→            subtitle="Find writers and stories that inspire you"
 82→          />
 83→        ) : (
 84→          <FlatList
 85→            data={[]}
 86→            renderItem={null}
 87→            showsVerticalScrollIndicator={false}
 88→            contentContainerStyle={styles.results}
 89→            ListHeaderComponent={
 90→              <>
 91→                {/* Users section */}
 92→                {activeTab !== 'posts' && users.length > 0 && (
 93→                  <View style={styles.section}>
 94→                    <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
 95→                      Users
 96→                    </Text>
 97→                    {users.map(u => (
 98→                      <Pressable
 99→                        key={u.id}
100→                        style={[styles.userRow, {borderBottomColor: colors.borderCard}]}
101→                        onPress={() =>
102→                          navigation.navigate('VisitProfile', {
103→                            userId: u.id,
104→                            username: u.username ?? undefined,
105→                          })
106→                        }>
107→                        <Avatar uri={u.image_url} name={u.name ?? undefined} size={40} />
108→                        <View style={styles.userInfo}>
109→                          <Text style={[styles.userName, {color: colors.textPrimary}]}>
110→                            {u.name || 'Unknown'}
111→                          </Text>
112→                          {u.username && (
113→                            <Text style={[styles.userHandle, {color: colors.textMuted}]}>
114→                              @{u.username}
115→                            </Text>
116→                          )}
117→                        </View>
118→                      </Pressable>
119→                    ))}
120→                  </View>
121→                )}
122→
123→                {/* Journals section */}
124→                {activeTab !== 'users' && journals.length > 0 && (
125→                  <View style={styles.section}>
126→                    <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
127→                      Posts
128→                    </Text>
129→                    {journals.map(j => (
130→                      <Pressable
131→                        key={j.id}
132→                        style={[styles.journalRow, {borderBottomColor: colors.borderCard}]}
133→                        onPress={() =>
134→                          navigation.navigate('PostDetail', {journalId: j.id})
135→                        }>
136→                        <Text
137→                          style={[styles.journalTitle, {color: colors.textPrimary}]}
138→                          numberOfLines={1}>
139→                          {j.title || 'Untitled Post'}
140→                        </Text>
141→                        <Text style={[styles.journalAuthor, {color: colors.textMuted}]}>
142→                          {j.users?.name || 'Unknown'}
143→                        </Text>
144→                      </Pressable>
145→                    ))}
146→                  </View>
147→                )}
148→
149→                {/* Empty results */}
150→                {activeTab !== 'posts' && users.length === 0 &&
151→                 activeTab !== 'users' && journals.length === 0 && (
152→                  <EmptyState
153→                    title="No results"
154→                    subtitle={`Nothing found for "${normalizedQuery}"`}
155→                  />
156→                )}
157→              </>
158→            }
159→          />
160→        )}
161→      </View>
162→    </SafeAreaView>
163→  );
164→}
