55→export const normalizeCount = (value: unknown): number => {
56→  const parsed = Number(value);
57→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
58→};
59→
60→export const resolveCount = (
61→  aggregate: Array<{count?: number}> | undefined,
62→  fallback?: number,
63→): number => {
64→  if (Array.isArray(aggregate) && aggregate.length > 0)
65→    return normalizeCount(aggregate[0]?.count);
66→  return normalizeCount(fallback);
67→};
